33	/// Normalize a comparison to always be "iv <op> value"
34	//  Return false if comparison is not with induction variable
35	//  Return false if comparison signedness doesn't match ForOp signedness
36	static bool normalizeForOpCmp(ForOp forOp, CmpIOp cmp,
37	                              ComparisonPredicate &normalizedPred, Value &rhs) {
38	  // Determine ForOp signedness based on unsignedCmp attribute
39	  Signedness forOpSignedness =
40	      forOp.getUnsignedCmp() ? Signedness::Unsigned : Signedness::Signed;
41	
42	  // Don't perform split if signedness of cmp doesn't match ForOp signedness
43	  if (cmp.getSignedness() != forOpSignedness)
44	    return false;
45	
46	  auto iv = forOp.getInductionVar();
47	  auto pred = cmp.getComparisonPredicate();
48	  if (cmp.getLhs() == iv) {
49	    normalizedPred = pred;
50	    rhs = cmp.getRhs();
51	    return true;
52	  } else if (cmp.getRhs() == iv) {
53	    rhs = cmp.getLhs();
54	    switch (pred) {
55	    case ComparisonPredicate::LESS_THAN:
56	      normalizedPred = ComparisonPredicate::GREATER_THAN;
57	      break;
58	    case ComparisonPredicate::LESS_THAN_OR_EQUAL:
59	      normalizedPred = ComparisonPredicate::GREATER_THAN_OR_EQUAL;
60	      break;
61	    case ComparisonPredicate::GREATER_THAN:
62	      normalizedPred = ComparisonPredicate::LESS_THAN;
63	      break;
64	    case ComparisonPredicate::GREATER_THAN_OR_EQUAL:
65	      normalizedPred = ComparisonPredicate::LESS_THAN_OR_EQUAL;
66	      break;
67	    default:
68	      return false;
69	    }
70	    return true;
71	  }
72	  return false;
73	}
74	
75	/// Return True if splitting loop for current branch seems profitable for
76	///  performance
77	static bool isSplitProfitable(ForOp forOp, IfOp ifOp, int threshold) {
78	  // If threshold is 1, splitting will occur regardless of the content of the
79	  // IfOp. In that case, we can short-circuit.
80	  if (threshold == 1)
81	    return true;
82	  auto countOps = [&](auto &opRange) {
83	    bool hasHeavyOps = false;
84	    int opCount = 0;
85	    for (Operation &op : opRange.getOps()) {
86	      hasHeavyOps |=
87	          isa<LoadPtrTkoOp, LoadViewTkoOp, StorePtrTkoOp, StoreViewTkoOp,
88	              MmaFOp, MmaIOp, ReduceOp, IfOp, ForOp>(op);
89	      opCount++;
90	    }
91	    return std::tuple(opCount - 1, hasHeavyOps);
92	  };
93	  auto [thenSize, hasHeavyOps] = countOps(ifOp.getThenRegion());
94	  int elseSize = 0;
95	  if (ifOp->getNumRegions() > 1) {
96	    bool elseHasHeavyOps = false;
97	    std::tie(elseSize, elseHasHeavyOps) = countOps(ifOp.getElseRegion());
98	    hasHeavyOps |= elseHasHeavyOps;
99	  }
100	
101	  // Only split loop if there are either many operations
102	  // inside either the then or else block, or if any op is "expensive"
103	  return thenSize >= threshold || elseSize >= threshold || hasHeavyOps;
104	}
105	
106	/// Check if an cuda_tile.if condition is a cmpi with induction variable.
107	//  Collect all branches with the same predicate into `ifOps` vector
108	static bool isSplittableCondition(ForOp forOp, IfOp ifOp,
109	                                  SmallPtrSet<Operation *, 4> &ifOps,
110	                                  ComparisonPredicate &predOut, Value &rhsOut,
111	                                  CmpIOp &cmpOpOut, bool &secondThen,
112	                                  bool &copyCmp, int threshold) {
113	  // Optimization hint says not to split loop at this branch
114	  if (!threshold)
115	    return false;
116	
117	  // Condition is not Cmp operation
118	  auto cmp = ifOp.getCondition().getDefiningOp<CmpIOp>();
119	  if (!cmp)
120	    return false;
121	
122	  ComparisonPredicate normalizedPred;
123	  Value rhs;
124	  // Normalizes the comparison so that induction variables are on the left.
125	  // If the comparison does not involve the induction variable (or not in a
126	  // tractable way), abort.
127	  if (!normalizeForOpCmp(forOp, cmp, normalizedPred, rhs))
128	    return false;
129	
130	  // Check that we compare induction variable with loop invariant
131	  auto rhsOp = rhs.getDefiningOp();
132	  if (rhsOp && forOp.getBody()->findAncestorOpInBlock(*rhsOp))
133	    return false;
134	
135	  // Check that predicate is supported and determine what block goes to the
136	  // first loop
137	  switch (normalizedPred) {
138	  case ComparisonPredicate::GREATER_THAN:
139	  case ComparisonPredicate::GREATER_THAN_OR_EQUAL:
140	    secondThen = true;
141	    break;
142	  case ComparisonPredicate::LESS_THAN:
143	  case ComparisonPredicate::LESS_THAN_OR_EQUAL:
144	    secondThen = false;
145	    break;
146	  default:
147	    return false;
148	  }
149	
150	  copyCmp = false;
151	  // Collect all IfOps with the same predicate and check for profitability
152	  bool isProfitable = false;
153	  Value pred = cmp->getResult(0);
154	  for (Operation *user : pred.getUsers()) {
155	    // In order to delete CmpOp and copy only one side of IfOp during cloning
156	    // IfOp should be in the same loop as CmpOp
157	    if (isa<IfOp>(user)) {
158	      // Check whether there is at least one IfOp using the same predicate that
159	      // would benefit from splitting.
160	      isProfitable |= isSplitProfitable(forOp, cast<IfOp>(user), threshold);
161	      // Collect IfOps for partial copy only directly nested into ForOp
162	      if (user->getParentOp() == forOp.getOperation()) {
163	        ifOps.insert(user);
164	        continue;
165	      }
166	      // If the IfOp is nested, it will not be split, so we fall through to
167	      // ensure the comparison is kept.
168	    }
169	    // CmpOp has other uses, except directly nested IfOps - need to keep it
170	    copyCmp = true;
171	  }
172	
173	  // No profitable IfOps found for splitting
174	  if (!isProfitable)
175	    return false;
176	
177	  cmpOpOut = cmp;
178	  predOut = normalizedPred;
179	  rhsOut = rhs;
180	  return true;
181	}
