183	/// Create a copy of the loop with new bounds & partial copy of if-blocks
184	static ForOp copyLoop(RewriterBase &rewriter, ForOp forOp, CmpIOp cmpOp,
185	                      SmallPtrSet<Operation *, 4> &ifOps,
186	                      SmallVector<Operation *> &opsToClone, Value lowerBound,
187	                      Value upperBound, ValueRange iterArgs, bool cloneThen) {
188	  Location loc = forOp.getLoc();
189	  Value step = forOp.getStep();
190	  IRMapping mapper;
191	  auto newLoop =
192	      ForOp::create(rewriter, loc, lowerBound, upperBound, step, iterArgs,
193	                    /*bodyBuilder=*/nullptr, forOp.getUnsignedCmp());
194	  rewriter.setInsertionPointToStart(newLoop.getBody());
195	
196	  for (auto [orig, repl] : llvm::zip(forOp.getBody()->getArguments(),
197	                                     newLoop.getBody()->getArguments()))
198	    mapper.map(orig, repl);
199	
200	  // Process all operations selected for copy
201	  for (Operation *op : opsToClone) {
202	    if (cmpOp.getOperation() == op) {
203	      // Replace CmpOp with constant value
204	      TileType constType = TileType::get({}, rewriter.getI1Type());
205	      llvm::APInt val(1, cloneThen ? 1 : 0);
206	      auto constAttr = DenseIntElementsAttr::get(constType, val);
207	      auto cmpConst =
208	          ConstantOp::create(rewriter, op->getLoc(), constType, constAttr);
209	      mapper.map(cmpOp.getResult(), cmpConst);
210	      continue;
211	    } else if (!ifOps.contains(op)) {
212	      rewriter.clone(*op, mapper);
213	      continue;
214	    }
215	    // Current operation is IfOp that we split
216	    IfOp ifOp = cast<IfOp>(op);
217	    bool is_continue = false;
218	    Region &region = cloneThen ? ifOp.getThenRegion() : ifOp.getElseRegion();
219	    for (Operation &subOp : region.front()) {
220	      // Copy all operations from one of the regions
221	      if (isa<ContinueOp>(subOp)) {
222	        rewriter.clone(subOp, mapper);
223	        // Stop cloning operations at ContinueOp
224	        is_continue = true;
225	        break;
226	      }
227	      if (isa<YieldOp>(subOp)) {
228	        // Map ifResult to the YieldOp
229	        auto yieldOp = cast<YieldOp>(subOp);
230	        for (auto [ifResult, yieldArg] :
231	             llvm::zip_equal(ifOp.getResults(), yieldOp.getOperands()))
232	          mapper.map(ifResult, mapper.lookupOrDefault(yieldArg));
233	      } else {
234	        // General operation
235	        rewriter.clone(subOp, mapper);
236	      }
237	    }
238	    // Continue was met inside if-block - don't need to copy operations below
239	    if (is_continue)
240	      break;
241	  }
242	  return newLoop;
243	}
244	
245	// Helper function to return if step is equal to one
246	static inline bool isConstOne(ConstantOp op) {
247	  auto type = op.getType().getElementType();
248	  auto intType = llvm::dyn_cast<IntegerType>(type);
249	  if (!intType)
250	    return false;
251	  DenseTypedElementsAttr cstAttr = op.getValue();
252	  if (cstAttr.size() != 1)
253	    return false;
254	  auto intData = cstAttr.tryGetValues<APInt>();
255	  if (succeeded(intData))
256	    return (*intData->begin() == 1);
257	  return false;
258	}
259	
260	/// Split the loop at the correct threshold based on predicate.
261	static void performLoopSplit(RewriterBase &rewriter, ForOp forOp,
262	                             ComparisonPredicate pred, Value splitValue,
263	                             SmallPtrSet<Operation *, 4> &ifOps, CmpIOp cmp,
264	                             bool secondThen, bool copyCmp) {
265	  Location loc = forOp.getLoc();
266	  Value step = forOp.getStep();
267	  auto constStep = llvm::dyn_cast<ConstantOp>(step.getDefiningOp());
268	  ValueRange iterArgs = forOp.getInitValues();
269	  Value lb = forOp.getLowerBound();
270	  Value ub = forOp.getUpperBound();
271	
272	  // Determine ForOp signedness based on unsignedCmp attribute
273	  Signedness forOpSignedness =
274	      forOp.getUnsignedCmp() ? Signedness::Unsigned : Signedness::Signed;
275	
276	  // Compute split point depending on predicate.
277	  // Increase splitPoint by 1 in the case of GT or LTE
278	  Value splitPoint = splitValue;
279	  if (pred == ComparisonPredicate::GREATER_THAN ||
280	      pred == ComparisonPredicate::LESS_THAN_OR_EQUAL) {
281	    TileType constType = llvm::dyn_cast<TileType>(step.getType());
282	    auto intType = llvm::dyn_cast<IntegerType>(constType.getElementType());
283	    llvm::APInt val(intType.getWidth(), 1);
284	    auto constAttr = DenseIntElementsAttr::get(constType, val);
285	    auto constOp = ConstantOp::create(rewriter, loc, constType, constAttr);
286	    splitPoint = AddIOp::create(rewriter, loc, splitValue, constOp);
287	  }
288	  if (!constStep || !isConstOne(constStep)) {
289	    // Step is not equal to one (or dynamic)
290	    // Need special handling, so that loop split point is aligned (i.e. == lb +
291	    // k * step) So, splitPoint = start + Ceil(splitPoint - lb, step) * step
292	    Value diff = SubIOp::create(rewriter, loc, splitPoint, lb);
293	    Value k = DivIOp::create(rewriter, loc, diff, step, forOpSignedness,
294	                             RoundingMode::POSITIVE_INF);
295	    Value kstep = MulIOp::create(rewriter, loc, k, step);
296	    splitPoint = AddIOp::create(rewriter, loc, lb, kstep);
297	  }
298	
299	  Value minSplitPoint =
300	      MinIOp::create(rewriter, loc, splitPoint, ub, forOpSignedness);
301	  Value maxSplitPoint =
302	      MaxIOp::create(rewriter, loc, splitPoint, lb, forOpSignedness);
303	
304	  ForOp firstLoop, secondLoop;
305	  Block *originalBody = forOp.getBody();
306	  SmallVector<Operation *> opsToClone;
307	  // Collect operations for cloning
308	  for (Operation &op : *originalBody) {
309	    if (copyCmp || (&op != cmp.getOperation()))
310	      opsToClone.push_back(&op);
311	  }
312	
313	  // First loop: before the condition flips true
314	  rewriter.setInsertionPoint(forOp);
315	  firstLoop = copyLoop(rewriter, forOp, cmp, ifOps, opsToClone, lb,
316	                       minSplitPoint, iterArgs, !secondThen);
317	  // Second loop: after the condition is true
318	  rewriter.setInsertionPointAfter(firstLoop);
319	  secondLoop = copyLoop(rewriter, forOp, cmp, ifOps, opsToClone, maxSplitPoint,
320	                        ub, firstLoop.getResults(), secondThen);
321	
322	  rewriter.replaceOp(forOp, secondLoop);
323	};
324	
325	/// Merge optimization hints - more precise hint (if any) gets priority
326	//  Default value is splitThreshold == 1 defined in pass options
327	//  Return threshold (minimum number of operations inside if-block)
328	//  that will be used for determine if splitting should be performed
329	//  1 - effectively enables splitting for any branch
330	static int getSplitThreshold(std::optional<int> entryHint,
331	                             std::optional<int> forHint,
332	                             std::optional<int> ifHint, int splitThreshold) {
333	  if (ifHint)
334	    return ifHint.value();
335	  if (forHint)
336	    return forHint.value();
337	  if (entryHint)
338	    return entryHint.value();
339	  return splitThreshold;
340	}
341	
342	static std::optional<int> getLoopSplitThresholdAttr(Operation *op) {
343	  std::optional<int> res = std::nullopt;
344	  Attribute loopSplitThreshold =
345	      op->getDiscardableAttr(kLoopSplitThresholdAttrName);
346	  if (loopSplitThreshold)
347	    res = cast<IntegerAttr>(loopSplitThreshold).getInt();
348	  return res;
349	}
350	
351	#define GEN_PASS_DEF_LOOPSPLITPASS
352	#include "cuda_tile/Dialect/CudaTile/Transforms/Passes.h.inc"
353	
354	struct LoopSplitPass : public impl::LoopSplitPassBase<LoopSplitPass> {
355	public:
356	  using impl::LoopSplitPassBase<LoopSplitPass>::LoopSplitPassBase;
357	
358	  void runOnOperation() override {
359	    Operation *op = getOperation();
360	    MLIRContext *ctx = &getContext();
361	    IRRewriter rewriter(ctx);
362	
363	    std::optional<int> entryHint = getLoopSplitThresholdAttr(op);
364	    op->walk([&](ForOp forOp) {
365	      std::optional<int> forHint = getLoopSplitThresholdAttr(forOp);
366	      forOp->walk([&](IfOp ifOp) {
367	        CmpIOp cmp;
368	        ComparisonPredicate pred;
369	        Value rhs;
370	        bool secondThen;
371	        bool copyCmp;
372	        std::optional<int> ifHint = getLoopSplitThresholdAttr(ifOp);
373	        SmallPtrSet<Operation *, 4> ifOps;
374	        if (isSplittableCondition(forOp, ifOp, ifOps, pred, rhs, cmp,
375	                                  secondThen, copyCmp,
376	                                  getSplitThreshold(entryHint, forHint, ifHint,
377	                                                    splitThreshold))) {
378	          rewriter.setInsertionPoint(forOp);
379	          performLoopSplit(rewriter, forOp, pred, rhs, ifOps, cmp, secondThen,
380	                           copyCmp);
381	          return WalkResult::interrupt();
382	        }
383	        return WalkResult::advance();
384	      });
385	      return WalkResult::advance();
386	    });
387	  }
388	};
389	
390	} // namespace mlir::cuda_tile
